export function initDropZone(dropZoneElement, dotNetHelper) {
    function prevent(e) {
        e.preventDefault();
        e.stopPropagation();
    }

    function onDragEnter(e) {
        prevent(e);
        dotNetHelper.invokeMethodAsync('OnDragEnter');
    }

    function onDragLeave(e) {
        prevent(e);
        // Only fire when leaving the drop zone itself, not child elements
        if (e.relatedTarget && dropZoneElement.contains(e.relatedTarget)) return;
        dotNetHelper.invokeMethodAsync('OnDragLeave');
    }

    function onDragOver(e) {
        prevent(e);
    }

    function onDrop(e) {
        prevent(e);
        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'unknown' });
        }
        dotNetHelper.invokeMethodAsync('OnFilesDropped', files);
    }

    dropZoneElement.addEventListener('dragenter', onDragEnter);
    dropZoneElement.addEventListener('dragleave', onDragLeave);
    dropZoneElement.addEventListener('dragover', onDragOver);
    dropZoneElement.addEventListener('drop', onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener('dragenter', onDragEnter);
            dropZoneElement.removeEventListener('dragleave', onDragLeave);
            dropZoneElement.removeEventListener('dragover', onDragOver);
            dropZoneElement.removeEventListener('drop', onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.TooLarge ? "file-error" : "")">
                @if (entry.TooLarge)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                        <span class="error-message">File exceeds 10 MB limit</span>
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    private record FileEntry(FileInfo Info, bool TooLarge);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/fileDropZone.js");
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter()
    {
        _isDragOver = true;
        StateHasChanged();
    }

    [JSInvokable]
    public void OnDragLeave()
    {
        _isDragOver = false;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<DroppedFileDto> droppedFiles)
    {
        _isDragOver = false;

        foreach (var dto in droppedFiles)
        {
            var info = new FileInfo(dto.Name, dto.Size, dto.Type);
            _files.Add(new FileEntry(info, dto.Size > MaxFileSize));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.TooLarge).Select(f => f.Info).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    // DTO for JS interop deserialization
    public class DroppedFileDto
    {
        public string Name { get; set; } = "";
        public long Size { get; set; }
        public string Type { get; set; } = "";
    }
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
    user-select: none;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-wrap: wrap;
    gap: 0.25rem;
    align-items: baseline;
}

.error-message {
    color: #dc3545;
    font-weight: 600;
    margin-left: 0.5rem;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.6rem;
    cursor: pointer;
    font-size: 0.85rem;
    flex-shrink: 0;
    margin-left: 1rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

